import re
import requests
from bs4 import BeautifulSoup
from html import unescape

class WechatContentExtractor:
    def __init__(self, url):
        self.url = url
        self.headers = {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/116.0.0.0 Safari/537.36 MicroMessenger/7.0.20.1781(0x6700143B)',
            'Referer': 'https://mp.weixin.qq.com/'
        }
        self.soup = None
        self._load_page()

    def _load_page(self):
        """智能页面加载系统"""
        try:
            response = requests.get(self.url, headers=self.headers, timeout=15)
            response.encoding = 'utf-8'
            raw_html = self._clean_html(response.text)

            # 处理微信特有的内容保护机制
            self.soup = BeautifulSoup(
                re.sub(r'<!--(?!<!)[^>]*-->', '', raw_html),  # 移除干扰性注释
                'lxml'
            )
        except Exception as e:
            raise RuntimeError(f"页面加载失败: {str(e)}")

    def _clean_html(self, html):
        """多层HTML清洗系统"""
        # 移除微信的干扰性元标签
        html = re.sub(r'<meta\s+name="(viewport|format-detection)"[^>]*>', '', html)

        # 解码HTML实体
        html = unescape(html)

        # 处理微信的随机干扰字符
        html = re.sub(r'[\x00-\x1F\x7F]', '', html)

        return html

    def _extract_main_title(self):
        """智能标题提取系统"""
        title_selectors = [
            {'name': 'h1', 'attrs': {'id': 'activity-name'}},  # 新版微信
            {'name': 'h1', 'attrs': {'class': 'rich_media_title'}},  # 旧版微信
            {'name': 'h2', 'attrs': {'id': 'shareTitle'}},  # 视频文章
            {'name': 'title'}  # 备用方案
        ]

        for selector in title_selectors:
            element = self.soup.find(**selector)
            if element:
                raw_title = element.get_text()
                # 多层标题清洗
                title = re.sub(r'\s*[\|｜]\s*微信.*$', '', raw_title)  # 移除尾部微信标识
                title = re.sub(r'[\n\r\t]+', ' ', title).strip()
                return title[:200]  # 限制最大长度

        return "未检测到标题"

    def _extract_content(self):
        """自适应正文提取引擎"""
        content_blocks = [
            self.soup.find('div', id='js_content'),  # 常规文章
            self.soup.find('div', class_='video_detail'),  # 视频内容
            self.soup.find('div', class_='rich_media_content')  # 旧版格式
        ]

        for content_div in content_blocks:
            if content_div:
                return self._process_content(content_div)

        return "<p>内容解析失败</p>"

    def _process_content(self, content_div):
        """深度内容处理系统"""
        # 移除干扰元素黑名单
        forbidden_tags = [
            'script', 'style', 'iframe', 'noscript',
            'button', 'input', 'form', 'ins', 'svg'
        ]
        for tag in forbidden_tags:
            [x.decompose() for x in content_div.find_all(tag)]

        # 转换图片系统
        for img in content_div.find_all('img'):
            if 'data-src' in img.attrs:
                img.attrs['src'] = img.attrs.pop('data-src')
            img.attrs['loading'] = 'lazy'  # 添加懒加载属性

        # 优化排版系统
        self._improve_typography(content_div)

        return str(content_div)

    def _improve_typography(self, element):
        """专业排版优化系统"""
        # 修复段落间距
        for p in element.find_all('p'):
            p.attrs['style'] = 'margin: 1em 0; line-height: 1.6;'

        # 标题层级处理
        heading_map = {
            'h1': 2,  # 避免与主标题重复
            'h2': 3,
            'h3': 4,
            'h4': 5
        }
        for tag, level in heading_map.items():
            for heading in element.find_all(tag):
                heading.name = f'h{level}'

        # 列表格式化
        for ul in element.find_all('ul'):
            ul.attrs['style'] = 'padding-left: 2em; list-style-type: disc;'
        for ol in element.find_all('ol'):
            ol.attrs['style'] = 'padding-left: 2em; list-style-type: decimal;'

    def save_article(self, output_format='html'):
        """智能保存系统"""
        title = self._extract_main_title()
        content = self._extract_content()

        # 生成标准化文件名
        filename = re.sub(r'[\\/*?:"<>|]', '', title)[:50]
        filename = filename.strip() or 'untitled'

        # 格式处理系统
        if output_format == 'html':
            full_html = f"""<!DOCTYPE html>
            <html>
            <head>
                <meta charset="utf-8">
                <title>{title}</title>
                <style>
                    body {{ max-width: 720px; margin: 0 auto; padding: 20px; }}
                    h1 {{ color: #222; border-bottom: 2px solid #eee; padding-bottom: 0.5em; }}
                    img {{ max-width: 100%; height: auto; margin: 1em 0; }}
                    blockquote {{ border-left: 4px solid #ddd; padding-left: 1em; color: #666; }}
                </style>
            </head>
            <body>
                <h1>{title}</h1>
                {content}
            </body>
            </html>
            """
            with open(f"{filename}.html", 'w', encoding='utf-8') as f:
                f.write(full_html)
            return f"{filename}.html"

        elif output_format == 'markdown':
            # 需要添加HTML到Markdown的转换逻辑
            pass

        else:
            raise ValueError("暂不支持该格式")

# 使用示例 ----------------------------
if __name__ == "__main__":
    article_url = "你的微信文章链接"

    try:
        extractor = WechatContentExtractor(article_url)
        saved_file = extractor.save_article()
        print(f"文章已保存为：{saved_file}")
    except Exception as e:
        print(f"保存失败：{str(e)}")
```

