```python
import os
import re
from pathlib import Path
from bs4 import BeautifulSoup
from docx import Document
from docx.enum.text import WD_PARAGRAPH_ALIGNMENT
from docx.shared import Pt, RGBColor
from weasyprint import HTML, CSS

class WechatArticleProcessor:
    def __init__(self, html_path):
        self.html_path = Path(html_path)
        self.output_dir = self.html_path.parent / "processed"
        self.output_dir.mkdir(exist_ok=True)

        with open(html_path, 'r', encoding='utf-8') as f:
            self.soup = BeautifulSoup(f.read(), 'lxml')

        self.title_hierarchy = []
        self._detect_headings()

    def _detect_headings(self):
        """智能标题层级检测系统"""
        heading_candidates = self.soup.find_all(['h1', 'h2', 'h3', 'h4', 'p', 'div'])

        for element in heading_candidates:
            heading_info = self._analyze_element(element)
            if heading_info:
                self._mark_heading(element, heading_info)
                self.title_hierarchy.append(heading_info)

    def _analyze_element(self, element):
        """分析元素是否为标题及其层级"""
        text = element.get_text().strip()
        if not text:
            return None

        # 规则1：标签类型判断
        if element.name in ['h1', 'h2', 'h3', 'h4']:
            return {
                'level': int(element.name[1]),
                'text': text,
                'type': 'html_tag'
            }

        # 规则2：样式特征分析
        style = element.get('style', '').lower()
        font_size = re.findall(r'font-size:\s*(\d+)px', style)
        if font_size:
            size = int(font_size[0])
            if size >= 20:
                return {'level': 2, 'text': text, 'type': 'font_size'}
            elif size >= 18:
                return {'level': 3, 'text': text, 'type': 'font_size'}

        # 规则3：类名特征分析
        class_mapping = {
            'section_title': 2,
            'subtitle': 3,
            'para-title': 2,
            'section-subtitle': 3
        }
        for cls, level in class_mapping.items():
            if cls in element.get('class', []):
                return {'level': level, 'text': text, 'type': 'class_name'}

        # 规则4：文本模式匹配
        patterns = [
            (r'^第[一二三四五六七八九十]+章\s', 2),
            (r'^[IVX]+\.\s', 2),
            (r'^\d+\.\d+\s', 3),
            (r'^•\s+', 4)
        ]
        for pattern, level in patterns:
            if re.match(pattern, text):
                return {'level': level, 'text': re.sub(pattern, '', text), 'type': 'text_pattern'}

        return None

    def _mark_heading(self, element, heading_info):
        """在HTML中标记标题层级"""
        new_tag = self.soup.new_tag(f'h{heading_info["level"]+1}')
        new_tag.string = heading_info['text']
        new_tag['class'] = f'heading-level-{heading_info["level"]}'
        element.replace_with(new_tag)

    def export_to_word(self):
        """生成带层级样式的Word文档"""
        doc = Document()

        # 添加主标题
        main_title = self.title_hierarchy[0]['text'] if self.title_hierarchy else "未命名文档"
        doc.add_heading(main_title, 0)

        # 设置样式
        styles = {
            2: ('一级副标题', 16, True, RGBColor(0, 51, 153)),
            3: ('二级副标题', 14, True, RGBColor(0, 102, 204)),
            4: ('三级副标题', 12, False, RGBColor(102, 153, 255))
        }

        # 添加内容
        for heading in self.title_hierarchy[1:]:
            level = heading['level']
            if level not in styles:
                continue

            style_name, font_size, bold, color = styles[level]
            p = doc.add_paragraph()
            p.style = style_name
            run = p.add_run(heading['text'])
            run.font.size = Pt(font_size)
            run.bold = bold
            run.font.color = color

            # 添加后续内容（示例）
            doc.add_paragraph("相关正文内容...")

        # 保存文件
        word_path = self.output_dir / f"{main_title}.docx"
        doc.save(word_path)
        return word_path

    def export_to_pdf(self):
        """生成带样式优化的PDF"""
        css = CSS(string='''
            @page { margin: 2cm; }
            body { font-family: 'SimSun'; line-height: 1.6; }
            .heading-level-2 { 
                font-size: 18pt; 
                color: #003399;
                border-bottom: 2px solid #eee;
                margin-top: 1.5em;
            }
            .heading-level-3 {
                font-size: 14pt;
                color: #0066cc;
                margin-top: 1em;
            }
            .heading-level-4 {
                font-size: 12pt;
                color: #6699ff;
                margin-left: 1em;
            }
        ''')

        html_content = str(self.soup)
        pdf_path = self.output_dir / f"{self.title_hierarchy[0]['text']}.pdf"
        HTML(string=html_content).write_pdf(pdf_path, stylesheets=[css])
        return pdf_path

    def generate_report(self):
        """生成层级结构报告"""
        report = {
            "main_title": self.title_hierarchy[0]['text'] if self.title_hierarchy else None,
            "subtitle_levels": {},
            "total_headings": len(self.title_hierarchy)
        }

        for heading in self.title_hierarchy[1:]:
            level = heading['level']
            if level not in report['subtitle_levels']:
                report['subtitle_levels'][level] = []
            report['subtitle_levels'][level].append({
                "text": heading['text'],
                "type": heading['type']
            })

        return report

# 使用示例 --------------------------------------------------
if __name__ == "__main__":
    # 初始化处理器
    processor = WechatArticleProcessor("saved_article.html")

    # 生成文档
    word_path = processor.export_to_word()
    pdf_path = processor.export_to_pdf()

    # 获取报告
    report = processor.generate_report()

    print("处理完成！")
    print(f"Word文档路径：{word_path}")
    print(f"PDF文档路径：{pdf_path}")
    print("\n标题层级分析报告：")
    print(json.dumps(report, indent=2, ensure_ascii=False))
```

