def check_integrity(self, original_html):
    """对比处理前后的关键元素"""
    original_soup = BeautifulSoup(original_html, 'lxml')
    check_points = {
        'headings': len(original_soup.find_all(['h1', 'h2', 'h3', 'h4'])),
        'images': len(original_soup.find_all('img')),
        'paragraphs': len(original_soup.find_all('p'))
    }

    processed_counts = {
        'headings': len(self.title_hierarchy),
        'images': len(self.soup.find_all('img')),
        'paragraphs': len(self.soup.find_all('p'))
    }

    return {
        'headings_match': check_points['headings'] == processed_counts['headings'],
        'images_match': check_points['images'] == processed_counts['images'],
        'paragraphs_diff': check_points['paragraphs'] - processed_counts['paragraphs']
    }
```

